                    continue
                if fnmatch.fnmatch(f, pattern) or pattern in f:
                    matches.append(os.path.join(root, f))
                if len(matches) >= limit:
                    return "\n".join(matches)
        return "\n".join(matches) if matches else "No files found"
    else:
        # content search (grep-like)
        import re
