                fp = os.path.join(root, f)
                try:
                    with open(fp, "r", encoding="utf-8", errors="replace") as fh:
                        for i, line in enumerate(fh, 1):
                            if regex.search(line):
                                matches.append(f"{fp}:{i}: {line.rstrip()}")
                                if len(matches) >= limit:
