    "penyemak": {"domain": "qa", "tools": ["terminal", "file"], "desc": "Auditor — testing, validation, release checks"},
}

def delegate_task(task: str, role: str = None) -> str:
    if not role:
        role = infer_role(task)
    agent = AGENTS.get(role)
    if not agent:
        return f"Unknown role: {role}"
    return f"Delegating to {role} ({agent['desc']})\nTask: {task}\nTools: {', '.join(agent['tools'])}"

def infer_role(task: str) -> str:
    task_lower = task.lower()
    if any(w in task_lower for w in ["code", "implement", "build", "write"]):
        return "tukang"
    if any(w in task_lower for w in ["security", "pentest", "scan", "vulnerability"]):
        return "hulubalang"
    if any(w in task_lower for w in ["research", "investigate", "search", "docs"]):
        return "pawang"
    if any(w in task_lower for w in ["deploy", "ci", "cd", "automate"]):
        return "syahbandar"
    if any(w in task_lower for w in ["database", "schema", "migration", "sql"]):
        return "bendahara"
    if any(w in task_lower for w in ["test", "validate", "review", "audit"]):
        return "penyemak"
    return "tukang"  # Default to builder
