import json
import urllib.request
import urllib.error

PROVIDERS = {
    "ollama": {"base": "https://jebat.online/ollama", "format": "ollama", "models": ["qwen2.5-coder:7b", "qwen2.5:14b"]},
    "openai": {"base": "https://api.openai.com/v1", "format": "openai", "models": ["gpt-4o", "gpt-4o-mini"]},
    "anthropic": {"base": "https://api.anthropic.com", "format": "anthropic", "models": ["claude-sonnet-4"]},
    "gemini": {"base": "https://generativelanguage.googleapis.com/v1beta", "format": "gemini", "models": ["gemini-2.0-flash"]},
    "openrouter": {"base": "https://openrouter.ai/api/v1", "format": "openai", "models": ["anthropic/claude-sonnet-4"]},
    "github": {"base": "https://models.github.ai/inference", "format": "openai", "models": ["openai/gpt-4o-mini"]},
}

class LLMRouter:
    def __init__(self, fallback_order=None):
        self.fallback_order = fallback_order or ["ollama", "openai", "anthropic", "gemini", "openrouter", "github"]

    def complete(self, prompt: str, system: str = None, provider: str = None, model: str = None) -> dict:
        providers_to_try = [provider] if provider else self.fallback_order

        for prov_name in providers_to_try:
            prov = PROVIDERS.get(prov_name)
            if not prov:
                continue
            try:
                result = self._call_provider(prov_name, prov, prompt, system, model)
                return {"provider": prov_name, "model": model or prov["models"][0], "content": result}
            except Exception as e:
                continue

        return {"error": "All providers failed"}

    def _call_provider(self, name, prov, prompt, system, model):
        model = model or prov["models"][0]

        if prov["format"] == "ollama":
            return self._call_ollama(prov["base"], model, prompt, system)
        elif prov["format"] == "openai":
            return self._call_openai(prov["base"], model, prompt, system)
        elif prov["format"] == "anthropic":
            return self._call_anthropic(prov["base"], model, prompt, system)
        elif prov["format"] == "gemini":
            return self._call_gemini(prov["base"], model, prompt, system)
        raise ValueError(f"Unknown format: {prov['format']}")

    def _call_ollama(self, base, model, prompt, system):
        payload = json.dumps({"model": model, "prompt": prompt, "stream": False}).encode()
        req = urllib.request.Request(f"{base}/api/generate", data=payload, headers={"Content-Type": "application/json"})
        with urllib.request.urlopen(req, timeout=120) as resp:
            return json.loads(resp.read())["response"]

    def _call_openai(self, base, model, prompt, system):
        messages = []
        if system: messages.append({"role": "system", "content": system})
        messages.append({"role": "user", "content": prompt})
        payload = json.dumps({"model": model, "messages": messages}).encode()
        req = urllib.request.Request(f"{base}/chat/completions", data=payload, headers={"Content-Type": "application/json"})
        with urllib.request.urlopen(req, timeout=120) as resp:
            return json.loads(resp.read())["choices"][0]["message"]["content"]

    def _call_anthropic(self, base, model, prompt, system):
        payload = json.dumps({"model": model, "max_tokens": 4096, "messages": [{"role": "user", "content": prompt}]}).encode()
        headers = {"Content-Type": "application/json", "x-api-key": "YOUR_KEY", "anthropic-version": "2023-06-01"}
        req = urllib.request.Request(f"{base}/v1/messages", data=payload, headers=headers)
        with urllib.request.urlopen(req, timeout=120) as resp:
            return json.loads(resp.read())["content"][0]["text"]

    def _call_gemini(self, base, model, prompt, system):
        payload = json.dumps({"contents": [{"parts": [{"text": prompt}]}]}).encode()
        req = urllib.request.Request(f"{base}/models/{model}:generateContent?key=YOUR_KEY", data=payload, headers={"Content-Type": "application/json"})
        with urllib.request.urlopen(req, timeout=120) as resp:
            return json.loads(resp.read())["candidates"][0]["content"]["parts"][0]["text"]
