// server.ts — Express TypeScript API
import express, { Request, Response, NextFunction } from "express";
import jwt from "jsonwebtoken";
import rateLimit from "express-rate-limit";

const app = express();
app.use(express.json());

// Rate Limiter
const limiter = rateLimit({
  windowMs: 60 * 1000,
  max: 120,
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: "Too many requests" },
});
app.use(limiter);

// Types
interface AuthRequest extends Request {
  user?: { id: string; email: string; role: string };
}

interface AppError extends Error {
  statusCode?: number;
  code?: string;
}

// JWT Middleware
const authenticate = (req: AuthRequest, res: Response, next: NextFunction) => {
  const token = req.headers.authorization?.replace("Bearer ", "");
  if (!token) return res.status(401).json({ error: "No token provided" });
  try {
    const decoded = jwt.verify(token, process.env.JWT_SECRET!) as any;
    req.user = decoded;
    next();
  } catch {
    res.status(401).json({ error: "Invalid token" });
  }
};

// Role Check
const authorize = (...roles: string[]) => (req: AuthRequest, res: Response, next: NextFunction) => {
  if (!req.user || !roles.includes(req.user.role)) {
    return res.status(403).json({ error: "Insufficient permissions" });
  }
  next();
};

// Error Handler
const errorHandler = (err: AppError, req: Request, res: Response, next: NextFunction) => {
  console.error(`[${req.method}] ${req.path} - ${err.message}`);
  res.status(err.statusCode || 500).json({
    error: err.message || "Internal server error",
    ...(process.env.NODE_ENV === "development" && { stack: err.stack }),
  });
};

// Routes
app.get("/health", (req, res) => {
  res.json({ status: "ok", timestamp: new Date().toISOString() });
});

app.get("/admin/users", authenticate, authorize("admin"), async (req: AuthRequest, res: Response) => {
  // Admin-only route
  res.json({ users: [], message: "Admin access granted" });
});

app.post("/items", authenticate, async (req: AuthRequest, res: Response) => {
  const { name, description, price } = req.body;
  if (!name || !price) {
    throw Object.assign(new Error("Name and price required"), { statusCode: 400 });
  }
  res.status(201).json({ id: crypto.randomUUID(), name, description, price, createdBy: req.user!.id });
});

app.use(errorHandler);
app.listen(3000, () => console.log("Server running on :3000"));
