// main.go — Go HTTP Server
package main

import (
    "context"
    "encoding/json"
    "log"
    "net/http"
    "os"
    "os/signal"
    "syscall"
    "time"
)

type Response struct {
    Status  string      `json:"status"`
    Data    interface{} `json:"data,omitempty"`
    Error   string      `json:"error,omitempty"`
}

type Server struct {
    router *http.ServeMux
}

func NewServer() *Server {
    s := &Server{router: http.NewServeMux()}
    s.routes()
    return s
}

func (s *Server) routes() {
    s.router.HandleFunc("/health", s.handleHealth())
    s.router.HandleFunc("/api/items", s.handleItems())
}

func (s *Server) handleHealth() http.HandlerFunc {
    return func(w http.ResponseWriter, r *http.Request) {
        writeJSON(w, http.StatusOK, Response{Status: "ok"})
    }
}

func (s *Server) handleItems() http.HandlerFunc {
    return func(w http.ResponseWriter, r *http.Request) {
        ctx, cancel := context.WithTimeout(r.Context(), 5*time.Second)
        defer cancel()

        select {
        case <-ctx.Done():
            writeJSON(w, http.StatusGatewayTimeout, Response{Error: "timeout"})
            return
        default:
        }

        switch r.Method {
        case http.MethodGet:
            writeJSON(w, http.StatusOK, Response{Status: "ok", Data: []string{"item1", "item2"}})
        case http.MethodPost:
            var body map[string]interface{}
            if err := json.NewDecoder(r.Body).Decode(&body); err != nil {
                writeJSON(w, http.StatusBadRequest, Response{Error: "invalid JSON"})
                return
            }
            writeJSON(w, http.StatusCreated, Response{Status: "created", Data: body})
        default:
            writeJSON(w, http.StatusMethodNotAllowed, Response{Error: "method not allowed"})
        }
    }
}

func loggingMiddleware(next http.Handler) http.Handler {
    return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
        start := time.Now()
        next.ServeHTTP(w, r)
        log.Printf("%s %s %s", r.Method, r.URL.Path, time.Since(start))
    })
}

func corsMiddleware(next http.Handler) http.Handler {
    return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
        w.Header().Set("Access-Control-Allow-Origin", "*")
        w.Header().Set("Access-Control-Allow-Methods", "GET, POST, PUT, DELETE, OPTIONS")
        w.Header().Set("Access-Control-Allow-Headers", "Content-Type, Authorization")
        if r.Method == http.MethodOptions {
            w.WriteHeader(http.StatusNoContent)
            return
        }
        next.ServeHTTP(w, r)
    })
}

func writeJSON(w http.ResponseWriter, status int, data interface{}) {
    w.Header().Set("Content-Type", "application/json")
    w.WriteHeader(status)
    json.NewEncoder(w).Encode(data)
}

func main() {
    s := NewServer()
    handler := corsMiddleware(loggingMiddleware(s.router))

    srv := &http.Server{Addr: ":3000", Handler: handler}

    go func() {
        log.Printf("Server starting on :3000")
        if err := srv.ListenAndServe(); err != http.ErrServerClosed {
            log.Fatalf("Server error: %v", err)
        }
    }()

    quit := make(chan os.Signal, 1)
    signal.Notify(quit, syscall.SIGINT, syscall.SIGTERM)
    <-quit

    log.Println("Shutting down gracefully...")
    ctx, cancel := context.WithTimeout(context.Background(), 30*time.Second)
    defer cancel()
    srv.Shutdown(ctx)
}
