// src/main.rs — Actix-web Server
use actix_web::{web, App, HttpServer, HttpResponse, middleware};
use serde::{Deserialize, Serialize};
use std::sync::Mutex;

#[derive(Debug, Serialize, Deserialize, Clone)]
struct Item {
    id: String,
    name: String,
    description: Option<String>,
    price: f64,
}

#[derive(Deserialize)]
struct CreateItem {
    name: String,
    description: Option<String>,
    price: f64,
}

struct AppState {
    items: Mutex<Vec<Item>>,
}

async fn health() -> HttpResponse {
    HttpResponse::Ok().json(serde_json::json!({"status": "ok"}))
}

async fn list_items(data: web::Data<AppState>) -> HttpResponse {
    let items = data.items.lock().unwrap();
    HttpResponse::Ok().json(&*items)
}

async fn create_item(data: web::Data<AppState>, body: web::Json<CreateItem>) -> HttpResponse {
    let item = Item {
        id: uuid::Uuid::new_v4().to_string(),
        name: body.name.clone(),
        description: body.description.clone(),
        price: body.price,
    };
    let mut items = data.items.lock().unwrap();
    items.push(item.clone());
    HttpResponse::Created().json(item)
}

async fn get_item(data: web::Data<AppState>, path: web::Path<String>) -> HttpResponse {
    let items = data.items.lock().unwrap();
    match items.iter().find(|i| i.id == *path) {
        Some(item) => HttpResponse::Ok().json(item),
        None => HttpResponse::NotFound().json(serde_json::json!({"error": "not found"})),
    }
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    let data = web::Data::new(AppState {
        items: Mutex::new(Vec::new()),
    });

    println!("Server starting on :3000");
    HttpServer::new(move || {
        App::new()
            .app_data(data.clone())
            .wrap(middleware::Logger::default())
            .route("/health", web::get().to(health))
            .route("/api/items", web::get().to(list_items))
            .route("/api/items", web::post().to(create_item))
            .route("/api/items/{id}", web::get().to(get_item))
    })
    .bind("0.0.0.0:3000")?
    .run()
    .await
}
