// ItemController.java — Spring Boot REST API
package com.jebat.api.controller;

import jakarta.validation.Valid;
import jakarta.validation.constraints.*;
import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;
import java.util.*;

@SpringBootApplication
public class JebatApi {
    public static void main(String[] args) {
        SpringApplication.run(JebatApi.class, args);
    }
}

@RestController
@RequestMapping("/api/items")
class ItemController {
    private final Map<String, Item> items = new HashMap<>();

    @GetMapping
    public List<Item> list() {
        return new ArrayList<>(items.values());
    }

    @GetMapping("/{id}")
    public ResponseEntity<Item> get(@PathVariable String id) {
        Item item = items.get(id);
        return item != null ? ResponseEntity.ok(item) : ResponseEntity.notFound().build();
    }

    @PostMapping
    public ResponseEntity<Item> create(@Valid @RequestBody CreateItemRequest req) {
        Item item = new Item(UUID.randomUUID().toString(), req.name, req.description, req.price);
        items.put(item.id, item);
        return ResponseEntity.status(HttpStatus.CREATED).body(item);
    }

    @PutMapping("/{id}")
    public ResponseEntity<Item> update(@PathVariable String id, @Valid @RequestBody CreateItemRequest req) {
        Item existing = items.get(id);
        if (existing == null) return ResponseEntity.notFound().build();
        existing.name = req.name;
        existing.description = req.description;
        existing.price = req.price;
        return ResponseEntity.ok(existing);
    }

    @DeleteMapping("/{id}")
    public ResponseEntity<Void> delete(@PathVariable String id) {
        return items.remove(id) != null ? ResponseEntity.noContent().build() : ResponseEntity.notFound().build();
    }
}

record Item(String id, String name, String description, double price) {}

record CreateItemRequest(
    @NotBlank @Size(max = 200) String name,
    String description,
    @Positive double price
) {}
