// server.cpp — Boost.Beast HTTP Server
#include <boost/beast/core.hpp>
#include <boost/beast/http.hpp>
#include <boost/asio/ip/tcp.hpp>
#include <nlohmann/json.hpp>
#include <iostream>
#include <string>
#include <vector>

namespace beast = boost::beast;
namespace http = beast::http;
namespace net = boost::asio;
using json = nlohmann::json;
using tcp = net::ip::tcp;

struct Item {
    std::string id;
    std::string name;
    std::string description;
    double price;
};

std::vector<Item> items;

class Session : public std::enable_shared_from_this<Session> {
    tcp::socket socket_;
    beast::flat_buffer buffer_;
    http::request<http::string_body> req_;
    http::response<http::string_body> res_;

public:
    explicit Session(tcp::socket socket) : socket_(std::move(socket)) {}

    void start() {
        auto self = shared_from_this();
        http::async_read(socket_, buffer_, req_,
            [self](beast::error_code ec, std::size_t) {
                if (!ec) self->handleRequest();
            });
    }

    void handleRequest() {
        res_.version(req_.version());
        res_.set(http::field::content_type, "application/json");

        if (req_.target() == "/health" && req_.method() == http::verb::get) {
            res_.result(http::status::ok);
            res_.body() = json({{"status", "ok"}}).dump();
        } else if (req_.target() == "/api/items" && req_.method() == http::verb::get) {
            json arr = json::array();
            for (const auto& item : items) {
                arr.push_back({{"id", item.id}, {"name", item.name}, {"price", item.price}});
            }
            res_.result(http::status::ok);
            res_.body() = arr.dump();
        } else {
            res_.result(http::status::not_found);
            res_.body() = json({{"error", "not found"}}).dump();
        }

        res_.prepare_payload();
        res_.keep_alive(req_.keep_alive());

        auto self = shared_from_this();
        http::async_write(socket_, res_,
            [self](beast::error_code ec, std::size_t) {
                self->socket_.shutdown(tcp::socket::shutdown_send, ec);
            });
    }
};

int main() {
    try {
        auto const address = net::ip::make_address("0.0.0.0");
        unsigned short const port = 3000;
        net::io_context ioc{1};
        tcp::acceptor acceptor{ioc, {address, port}};

        std::cout << "Server running on :" << port << std::endl;

        for (;;) {
            auto socket = acceptor.accept();
            std::make_shared<Session>(std::move(socket))->start();
        }
    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
        return 1;
    }
}
