from fastapi import FastAPI, WebSocket, WebSocketDisconnect
from dataclasses import dataclass, field
from datetime import datetime
import asyncio

app = FastAPI()

@dataclass
class Connection:
    ws: WebSocket
    user_id: str
    username: str
    rooms: set = field(default_factory=set)
    last_hb: datetime = field(default_factory=datetime.utcnow)

class Manager:
    def __init__(self):
        self.conns: dict[str, Connection] = {}
        self.rooms: dict[str, set[str]] = {}

    async def connect(self, ws, uid, name):
        await ws.accept()
        self.conns[uid] = Connection(ws=ws, user_id=uid, username=name)
        await self.broadcast({"type": "system", "text": f"{name} joined"})

    async def disconnect(self, uid):
        conn = self.conns.pop(uid, None)
        if conn:
            for r in conn.rooms:
                self.rooms.get(r, set()).discard(uid)

    async def broadcast(self, msg, exclude=None):
        for uid, c in self.conns.items():
            if uid != exclude:
                try: await c.ws.send_json(msg)
                except: pass

    async def send_room(self, room, msg, exclude=None):
        for uid in self.rooms.get(room, set()):
            if uid != exclude and uid in self.conns:
                try: await self.conns[uid].ws.send_json(msg)
                except: pass

    async def join_room(self, uid, room):
        c = self.conns.get(uid)
        if c:
            c.rooms.add(room)
            self.rooms.setdefault(room, set()).add(uid)

mgr = Manager()

async def heartbeat_check():
    while True:
        now = datetime.utcnow()
        for uid, c in list(mgr.conns.items()):
            if (now - c.last_hb).seconds > 60:
                await mgr.disconnect(uid)
        await asyncio.sleep(30)

@app.on_event("startup")
async def startup():
    asyncio.create_task(heartbeat_check())

@app.websocket("/ws/{uid}/{name}")
async def ws_endpoint(ws: WebSocket, uid: str, name: str):
    await mgr.connect(ws, uid, name)
    try:
        while True:
            data = await ws.receive_json()
            if data["type"] == "heartbeat":
                mgr.conns[uid].last_hb = datetime.utcnow()
            elif data["type"] == "message":
                await mgr.send_room(data.get("room", "general"), {
                    "type": "message", "user_id": uid, "username": name,
                    "content": data["content"]
                }, exclude=uid)
            elif data["type"] == "join_room":
                await mgr.join_room(uid, data["room"])
    except WebSocketDisconnect:
        await mgr.disconnect(uid)
