import redis, json, hashlib, functools, time
from typing import Any, Optional

class CircuitBreaker:
    def __init__(self, threshold=5, recovery=30):
        self.failures = 0; self.threshold = threshold; self.recovery = recovery
        self.last_failure = 0; self.state = "closed"

    def call(self, func, *args, **kwargs):
        if self.state == "open":
            if time.time() - self.last_failure > self.recovery:
                self.state = "half-open"
            else:
                raise Exception("Circuit breaker OPEN")
        try:
            result = func(*args, **kwargs)
            if self.state == "half-open":
                self.state = "closed"; self.failures = 0
            return result
        except Exception:
            self.failures += 1; self.last_failure = time.time()
            if self.failures >= self.threshold: self.state = "open"
            raise

class CacheLayer:
    def __init__(self, url="redis://localhost:6379/0"):
        self.r = redis.from_url(url, decode_responses=True)
        self.breaker = CircuitBreaker()
        self.default_ttl = 3600

    def _key(self, prefix, *args, **kwargs):
        h = hashlib.md5(json.dumps({"a": args, "k": kwargs}, sort_keys=True, default=str).encode()).hexdigest()[:12]
        return f"jebat:{prefix}:{h}"

    def get(self, key):
        try: return json.loads(self.breaker.call(self.r.get, key))
        except: return None

    def set(self, key, value, ttl=None):
        try: self.breaker.call(self.r.setex, key, ttl or self.default_ttl, json.dumps(value, default=str))
        except: pass

    def delete_pattern(self, pattern):
        try:
            keys = self.breaker.call(self.r.keys, pattern)
            if keys: self.breaker.call(self.r.delete, *keys)
        except: pass

    def invalidate(self, entity_type, entity_id=None):
        self.delete_pattern(f"jebat:{entity_type}:{entity_id + ':*' if entity_id else '*'}")

    def cached(self, prefix, ttl=None):
        def deco(func):
            @functools.wraps(func)
            async def wrapper(*args, **kwargs):
                key = self._key(prefix, *args, **kwargs)
                result = self.get(key)
                if result is not None: return result
                result = await func(*args, **kwargs)
                self.set(key, result, ttl or self.default_ttl)
                return result
            return wrapper
        return deco
