import re, urllib.parse, ssl, socket
from dataclasses import dataclass
from typing import List
from enum import Enum

class Severity(Enum):
    CRITICAL = "critical"; HIGH = "high"; MEDIUM = "medium"; LOW = "low"; INFO = "info"

@dataclass
class Finding:
    vuln_type: str; severity: Severity; title: str
    description: str; evidence: str; remediation: str; cwe: str = ""

class OWASPScanner:
    def __init__(self, url):
        self.target = url.rstrip("/"); self.findings: List[Finding] = []
        self.hdr = {"User-Agent": "JEBAT-Scanner/1.0"}

    def scan_all(self):
        for check in [self._headers, self._ssl, self._sqli, self._xss, self._redirects, self._cors]:
            try: check()
            except: pass
        return self.findings

    def _headers(self):
        import urllib.request
        resp = urllib.request.urlopen(urllib.request.Request(self.target, headers=self.hdr), timeout=10)
        hdrs = {k.lower(): v for k, v in resp.headers.items()}
        for h, (t, s, c) in {
            "strict-transport-security": ("Missing HSTS", Severity.MEDIUM, "CWE-523"),
            "x-content-type-options": ("Missing X-Content-Type-Options", Severity.LOW, "CWE-693"),
            "x-frame-options": ("Missing X-Frame-Options", Severity.MEDIUM, "CWE-1021"),
            "content-security-policy": ("Missing CSP", Severity.MEDIUM, "CWE-693"),
        }.items():
            if h not in hdrs:
                self.findings.append(Finding("missing_header", s, t, f"{h} not set", str(list(hdrs.keys())), f"Add {h}", c))

    def _ssl(self):
        from urllib.parse import urlparse
        host = urlparse(self.target).hostname
        ctx = ssl.create_default_context()
        with socket.create_connection((host, 443), timeout=10) as sock:
            with ctx.wrap_socket(sock, server_hostname=host) as ssock:
                if ssock.version() in ("TLSv1", "TLSv1.1"):
                    self.findings.append(Finding("weak_tls", Severity.HIGH, f"Deprecated {ssock.version()}", "Uses deprecated TLS", str(ssock.cipher()), "Use TLSv1.2+", "CWE-326"))

    def _sqli(self):
        import urllib.request
        for p in ["'", "1' OR '1'='1", "'; DROP TABLE--"]:
            try:
                body = urllib.request.urlopen(urllib.request.Request(f"{self.target}/?id={urllib.parse.quote(p)}", headers=self.hdr), timeout=10).read().decode(errors="ignore")
                if re.search(r"SQL syntax|ORA-\d{5}|PostgreSQL|sqlite3|Unclosed", body, re.I):
                    self.findings.append(Finding("sqli", Severity.CRITICAL, "SQL Injection", "DB error exposed", p, "Use parameterized queries", "CWE-89"))
                    return
            except: pass

    def _xss(self):
        import urllib.request
        for p in ['<script>alert(1)</script>', '<img src=x onerror=alert(1)>']:
            try:
                body = urllib.request.urlopen(urllib.request.Request(f"{self.target}/?q={urllib.parse.quote(p)}", headers=self.hdr), timeout=10).read().decode(errors="ignore")
                if p in body:
                    self.findings.append(Finding("xss", Severity.HIGH, "Reflected XSS", "Input reflected unsanitized", p, "Encode output, add CSP", "CWE-79"))
                    return
            except: pass

    def _redirects(self):
        import urllib.request
        for path in ["/redirect?url=https://evil.com"]:
            try:
                resp = urllib.request.urlopen(urllib.request.Request(self.target + path, headers=self.hdr), timeout=5)
                if "evil.com" in resp.url:
                    self.findings.append(Finding("redirect", Severity.MEDIUM, "Open redirect", "Redirects to attacker URL", resp.url, "Validate targets", "CWE-601"))
            except: pass

    def _cors(self):
        import urllib.request
        req = urllib.request.Request(self.target, headers={**self.hdr, "Origin": "https://evil.com"})
        resp = urllib.request.urlopen(req, timeout=10)
        acao = resp.headers.get("Access-Control-Allow-Origin", "")
        if acao == "*":
            self.findings.append(Finding("cors", Severity.MEDIUM, "CORS any origin", "ACAO is *", acao, "Restrict origins", "CWE-942"))
        elif "evil.com" in acao:
            self.findings.append(Finding("cors", Severity.HIGH, "CORS reflects origin", "Reflects attacker origin", acao, "Validate Origin", "CWE-942"))

    def report(self):
        lines = [f"OWASP Scan - {self.target}", "=" * 50]
        for sev in ["critical", "high", "medium", "low", "info"]:
            items = [f for f in self.findings if f.severity.value == sev]
            if items:
                lines.append(f"\n[{sev.upper()}] ({len(items)})")
                for f in items:
                    lines.append(f"  - {f.title}: {f.description}")
                    lines.append(f"    Fix: {f.remediation}")
                    if f.cwe: lines.append(f"    {f.cwe}")
        lines.append(f"\nTotal: {len(self.findings)} findings")
        return "\n".join(lines)
