import socket, concurrent.futures, ssl, time
from dataclasses import dataclass
from typing import List, Optional

KNOWN = {21:"FTP",22:"SSH",25:"SMTP",53:"DNS",80:"HTTP",443:"HTTPS",3306:"MySQL",5432:"PostgreSQL",6379:"Redis",8080:"HTTP-Alt",27017:"MongoDB"}

@dataclass
class Result:
    port: int; state: str; service: str; banner: str = ""; ms: float = 0.0

class Scanner:
    def __init__(self, target, threads=100, timeout=1.0):
        self.target = target; self.threads = threads; self.timeout = timeout
        self.ip = socket.gethostbyname(target); self.results: List[Result] = []

    def _scan(self, port) -> Optional[Result]:
        start = time.time()
        try:
            s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
            s.settimeout(self.timeout)
            if s.connect_ex((self.ip, port)) == 0:
                banner = self._banner(s, port)
                return Result(port, "open", KNOWN.get(port, "unknown"), banner[:60], round((time.time()-start)*1000, 1))
            s.close()
        except: pass
        return None

    def _banner(self, s, port):
        try:
            if port in (443, 8443):
                ctx = ssl.create_default_context(); ctx.check_hostname = False; ctx.verify_mode = ssl.CERT_NONE
                return ctx.wrap_socket(s, server_hostname=self.target).version() or ""
            s.sendall(b"HEAD / HTTP/1.0\r\nHost: " + self.target.encode() + b"\r\n\r\n")
            return s.recv(1024).decode(errors="ignore").strip()
        except: return ""

    def scan(self, ports=None):
        if not ports: ports = list(range(1, 1024)) + list(KNOWN.keys())
        with concurrent.futures.ThreadPoolExecutor(max_workers=self.threads) as pool:
            for r in filter(None, pool.map(self._scan, ports)):
                self.results.append(r)
        self.results.sort(key=lambda r: r.port)
        return self.results

    def report(self):
        lines = [f"Scan: {self.target} ({self.ip})", "=" * 50]
        for r in self.results: lines.append(f"  {r.port:>5}/tcp  {r.state}  {r.service}  {r.banner}")
        lines.append(f"\nOpen: {len(self.results)}")
        return "\n".join(lines)
