@dataclass
class CertInfo:
    subject: str; issuer: str; not_after: str; days_left: int; san: List[str]

@dataclass
class TLSInfo:
    protocol: str; cipher: str; bits: int

class SSLAnalyzer:
    def __init__(self, host, port=443):
        self.host = host; self.port = port
        self.cert: CertInfo = None; self.tls: TLSInfo = None; self.issues: List[str] = []

    def analyze(self):
        ctx = ssl.create_default_context()
        with socket.create_connection((self.host, self.port), timeout=10) as sock:
            with ctx.wrap_socket(sock, server_hostname=self.host) as ssock:
                cert = ssock.getpeercert()
                cipher = ssock.cipher()
                subj = dict(x[0] for x in cert["subject"])
                issuer = dict(x[0] for x in cert["issuer"])
                not_after = datetime.datetime.strptime(cert["notAfter"], "%b %d %H:%M:%S %Y %Z")
                days = (not_after - datetime.datetime.utcnow()).days
                san = [e[1] for e in cert.get("subjectAltName", ())]
                self.cert = CertInfo(subj.get("commonName",""), issuer.get("organizationName",""), cert["notAfter"], days, san)
                self.tls = TLSInfo(ssock.version(), cipher[0], cipher[2])
                if days < 30: self.issues.append(f"CRITICAL: Expires in {days}d")
                elif days < 90: self.issues.append(f"WARNING: Expires in {days}d")
                if cipher[0] and any(w in cipher[0].upper() for w in ["RC4","DES","NULL","EXPORT"]):
                    self.issues.append(f"WEAK CIPHER: {cipher[0]}")
        # Check deprecated protocols
        for proto in ["SSLv3", "TLSv1", "TLSv1.1"]:
            try:
                ctx2 = ssl.SSLContext(ssl.PROTOCOL_TLS_CLIENT); ctx2.check_hostname = False; ctx2.verify_mode = ssl.CERT_NONE
                with socket.create_connection((self.host, self.port), timeout=5) as s:
                    with ctx2.wrap_socket(s, server_hostname=self.host) as ss:
                        if ss.version() == proto: self.issues.append(f"WEAK PROTOCOL: {proto}")
            except: pass
        return {"cert": self.cert, "tls": self.tls, "issues": self.issues, "grade": self._grade()}

    def _grade(self):
        if any("CRITICAL" in i for i in self.issues): return "F"
        if any("WEAK" in i for i in self.issues): return "C"
        if any("WARNING" in i for i in self.issues): return "B"
        return "A+"

    def report(self):
        lines = [f"SSL/TLS: {self.host}:{self.port}", "=" * 50]
        if self.cert: lines += [f"  Subject: {self.cert.subject}", f"  Issuer: {self.cert.issuer}", f"  Expires: {self.cert.not_after}", f"  Days: {self.cert.days_left}", f"  SAN: {', '.join(self.cert.san[:5])}"]
        if self.tls: lines += [f"  Protocol: {self.tls.protocol}", f"  Cipher: {self.tls.cipher} ({self.tls.bits}-bit)"]
        if self.issues: lines += ["\nIssues:"] + [f"  - {i}" for i in self.issues]
        lines.append(f"\nGrade: {self._grade()}")
        return "\n".join(lines)
