import re
from dataclasses import dataclass, field
from typing import List

@dataclass
class VitalResult:
    metric: str; value: float; unit: str; rating: str; recs: List[str] = field(default_factory=list)

class WebVitalsAnalyzer:
    def analyze(self, html):
        return [self._lcp(html), self._cls(html), self._fid(html), self._fcp(html), self._ttfb(html)]

    def _lcp(self, html):
        recs, s = [], 0
        if re.search(r'<link[^>]*rel=["\']stylesheet["\']', html): s += 1; recs.append("Move non-critical CSS to async/defer")
        if re.search(r'<img', html) and 'preload' not in html: s += 1; recs.append("Add preload for above-the-fold images")
        if '<style>' not in html: s += 1; recs.append("Inline critical CSS")
        val = 2.5 + s * 0.5
        return VitalResult("LCP", round(val, 1), "s", "good" if val <= 2.5 else "poor", recs)

    def _cls(self, html):
        recs, s = [], 0
        for img in re.findall(r'<img[^>]*>', html):
            if 'width=' not in img or 'height=' not in img: s += 1; recs.append("Add width/height to images"); break
        if 'font-display' not in html and '@font-face' in html: s += 1; recs.append("Add font-display: swap")
        val = 0.05 + s * 0.05
        return VitalResult("CLS", round(val, 3), "", "good" if val <= 0.1 else "poor", recs)

    def _fid(self, html):
        recs = []
        blocking = [s for s in re.findall(r'<script[^>]*>', html) if 'async' not in s and 'defer' not in s and 'src=' in s]
        if blocking: recs.append(f"{len(blocking)} blocking scripts")
        return VitalResult("FID", 50 + len(blocking) * 30, "ms", "good" if len(blocking) < 2 else "poor", recs)

    def _fcp(self, html):
        recs = []
        if 'preconnect' not in html: recs.append("Add preconnect hints")
        return VitalResult("FCP", 1.8, "s", "good", recs)

    def _ttfb(self, html):
        return VitalResult("TTFB", 0.8, "s", "good", [])

    def report(self, results):
        lines = ["Core Web Vitals", "=" * 50]
        for r in results:
            lines.append(f"  {'OK' if r.rating == 'good' else 'FAIL'} {r.metric}: {r.value}{r.unit} ({r.rating})")
            for rec in r.recs: lines.append(f"    -> {rec}")
        return "\n".join(lines)
