import re
from dataclasses import dataclass
from typing import List

@dataclass
class SEOIssue:
    cat: str; sev: str; title: str; desc: str; rec: str

class SEOAuditor:
    def __init__(self, html, url=""):
        self.html = html; self.url = url; self.issues: List[SEOIssue] = []

    def _add(self, cat, sev, title, desc, rec):
        self.issues.append(SEOIssue(cat, sev, title, desc, rec))

    def audit(self):
        # Title
        m = re.search(r'<title[^>]*>(.*?)</title>', self.html, re.DOTALL | re.I)
        if not m: self._add("title", "critical", "Missing title", "No title tag", "Add 50-60 char title")
        else:
            t = m.group(1).strip()
            if len(t) < 30: self._add("title", "warning", "Title too short", f"{len(t)} chars", "Aim for 50-60")
            if len(t) > 60: self._add("title", "warning", "Title too long", f"{len(t)} chars", "Keep under 60")
        # Meta
        dm = re.search(r'<meta[^>]*name=["\']description["\'][^>]*content=["\']([^"\']*)["\']', self.html, re.I)
        if not dm: self._add("meta", "critical", "Missing description", "No meta desc", "Add 150-160 char desc")
        else:
            d = dm.group(1).strip()
            if len(d) < 120: self._add("meta", "warning", "Desc too short", f"{len(d)} chars", "Aim for 150-160")
            if len(d) > 160: self._add("meta", "warning", "Desc too long", f"{len(d)} chars", "Keep under 160")
        # Headings
        h1s = re.findall(r'<h1[^>]*>', self.html, re.I)
        if not h1s: self._add("headings", "critical", "Missing H1", "No H1", "Add exactly one H1")
        elif len(h1s) > 1: self._add("headings", "warning", "Multiple H1", f"{len(h1s)} found", "Use one H1")
        # Images
        imgs = re.findall(r'<img[^>]*>', self.html, re.I)
        no_alt = [i for i in imgs if 'alt=' not in i.lower()]
        if no_alt: self._add("images", "warning", f"{len(no_alt)} missing alt", "Images lack alt text", "Add descriptive alt text")
        # Canonical
        if 'rel="canonical"' not in self.html and "rel='canonical'" not in self.html:
            self._add("canonical", "warning", "Missing canonical", "No canonical URL", "Add canonical link")
        # Schema
        if 'application/ld+json' not in self.html:
            self._add("schema", "warning", "No structured data", "No JSON-LD", "Add JSON-LD schema")
        # OG
        for tag in ["og:title", "og:description", "og:image"]:
            if f'property="{tag}"' not in self.html:
                self._add("social", "warning", f"Missing {tag}", "OG tag missing", f"Add {tag}"); break
        # Mobile
        if 'viewport' not in self.html.lower():
            self._add("mobile", "critical", "Missing viewport", "Not mobile-ready", "Add viewport meta")
        # Lang
        if '<html' in self.html and 'lang=' not in self.html.lower():
            self._add("a11y", "warning", "Missing lang", "No lang attr", 'Add lang="en"')
        return self.issues

    def report(self):
        lines = ["SEO Audit", "=" * 50]
        for cat in sorted(set(i.cat for i in self.issues)):
            items = [i for i in self.issues if i.cat == cat]
            lines.append(f"\n{cat.upper()}:")
            for i in items: lines += [f"  [{i.sev.upper()}] {i.title}", f"    -> {i.rec}"]
        lines.append(f"\nTotal: {len(self.issues)} issues")
        return "\n".join(lines)
