import express, { Request, Response, NextFunction } from "express";
import jwt from "jsonwebtoken";
import rateLimit from "express-rate-limit";

const app = express();
app.use(express.json());
app.use(rateLimit({ windowMs: 60000, max: 120 }));

interface AuthRequest extends Request {
  user?: { id: string; email: string; role: string };
}

const authenticate = (req: AuthRequest, res: Response, next: NextFunction) => {
  const token = req.headers.authorization?.replace("Bearer ", "");
  if (!token) return res.status(401).json({ error: "No token" });
  try {
    req.user = jwt.verify(token, process.env.JWT_SECRET!) as any;
    next();
  } catch { res.status(401).json({ error: "Invalid token" }); }
};

const authorize = (...roles: string[]) => (req: AuthRequest, res: Response, next: NextFunction) => {
  if (!req.user || !roles.includes(req.user.role))
    return res.status(403).json({ error: "Forbidden" });
  next();
};

app.get("/health", (req, res) => res.json({ status: "ok" }));
app.get("/admin", authenticate, authorize("admin"), (req, res) => res.json({ ok: true }));
app.get("/users", authenticate, (req, res) => res.json({ user: req.user }));

app.listen(3000, () => console.log("Server on :3000"));
