package main

import (
    "context"
    "encoding/json"
    "log"
    "net/http"
    "os"
    "os/signal"
    "syscall"
    "time"
)

type Response struct {
    Status string      `json:"status"`
    Data   interface{} `json:"data,omitempty"`
    Error  string      `json:"error,omitempty"`
}

func writeJSON(w http.ResponseWriter, status int, data interface{}) {
    w.Header().Set("Content-Type", "application/json")
    w.WriteHeader(status)
    json.NewEncoder(w).Encode(data)
}

func logging(next http.Handler) http.Handler {
    return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
        start := time.Now()
        next.ServeHTTP(w, r)
        log.Printf("%s %s %s", r.Method, r.URL.Path, time.Since(start))
    })
}

func healthHandler(w http.ResponseWriter, r *http.Request) {
    writeJSON(w, 200, Response{Status: "ok"})
}

func itemsHandler(w http.ResponseWriter, r *http.Request) {
    ctx, cancel := context.WithTimeout(r.Context(), 5*time.Second)
    defer cancel()
    select {
    case <-ctx.Done():
        writeJSON(w, 504, Response{Error: "timeout"})
        return
    default:
    }
    switch r.Method {
    case http.MethodGet:
        writeJSON(w, 200, Response{Status: "ok", Data: []string{"item1"}})
    case http.MethodPost:
        var body map[string]interface{}
        json.NewDecoder(r.Body).Decode(&body)
        writeJSON(w, 201, Response{Status: "created", Data: body})
    default:
        writeJSON(w, 405, Response{Error: "method not allowed"})
    }
}

func main() {
    mux := http.NewServeMux()
    mux.HandleFunc("/health", healthHandler)
    mux.HandleFunc("/api/items", itemsHandler)
    srv := &http.Server{Addr: ":3000", Handler: logging(mux)}
    go func() {
        log.Println("Server on :3000")
        srv.ListenAndServe()
    }()
    quit := make(chan os.Signal, 1)
    signal.Notify(quit, syscall.SIGINT, syscall.SIGTERM)
    <-quit
    log.Println("Shutting down...")
    ctx, cancel := context.WithTimeout(context.Background(), 30*time.Second)
    defer cancel()
    srv.Shutdown(ctx)
}
