use actix_web::{web, App, HttpServer, HttpResponse, middleware};
use serde::{Deserialize, Serialize};
use std::sync::Mutex;

#[derive(Debug, Serialize, Deserialize, Clone)]
struct Item { id: String, name: String, price: f64 }

#[derive(Deserialize)]
struct CreateItem { name: String, price: f64 }

struct AppState { items: Mutex<Vec<Item>> }

async fn health() -> HttpResponse {
    HttpResponse::Ok().json(serde_json::json!({"status": "ok"}))
}

async fn list_items(data: web::Data<AppState>) -> HttpResponse {
    let items = data.items.lock().unwrap();
    HttpResponse::Ok().json(&*items)
}

async fn create_item(data: web::Data<AppState>, body: web::Json<CreateItem>) -> HttpResponse {
    let item = Item {
        id: uuid::Uuid::new_v4().to_string(),
        name: body.name.clone(),
        price: body.price,
    };
    data.items.lock().unwrap().push(item.clone());
    HttpResponse::Created().json(item)
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    let data = web::Data::new(AppState { items: Mutex::new(Vec::new()) });
    HttpServer::new(move || {
        App::new()
            .app_data(data.clone())
            .wrap(middleware::Logger::default())
            .route("/health", web::get().to(health))
            .route("/api/items", web::get().to(list_items))
            .route("/api/items", web::post().to(create_item))
    })
    .bind("0.0.0.0:3000")?
    .run()
    .await
}
