#include <boost/beast/core.hpp>
#include <boost/beast/http.hpp>
#include <boost/asio/ip/tcp.hpp>
#include <nlohmann/json.hpp>
#include <iostream>
#include <vector>

namespace beast = boost::beast;
namespace http = beast::http;
namespace net = boost::asio;
using json = nlohmann::json;
using tcp = net::ip::tcp;

struct Item { std::string id, name; double price; };
std::vector<Item> items;

class Session : public std::enable_shared_from_this<Session> {
    tcp::socket socket_;
    beast::flat_buffer buffer_;
    http::request<http::string_body> req_;
    http::response<http::string_body> res_;
public:
    explicit Session(tcp::socket socket) : socket_(std::move(socket)) {}
    void start() {
        auto self = shared_from_this();
        http::async_read(socket_, buffer_, req_,
            [self](auto ec, auto) { if (!ec) self->handle(); });
    }
    void handle() {
        res_.version(req_.version());
        res_.set(http::field::content_type, "application/json");
        if (req_.target() == "/health") {
            res_.result(http::status::ok);
            res_.body() = json({{"status","ok"}}).dump();
        } else {
            res_.result(http::status::not_found);
            res_.body() = json({{"error","not found"}}).dump();
        }
        res_.prepare_payload();
        auto self = shared_from_this();
        http::async_write(socket_, res_,
            [self](auto, auto) { self->socket_.shutdown(tcp::socket::shutdown_send); });
    }
};

int main() {
    net::io_context ioc{1};
    tcp::acceptor acceptor{ioc, {tcp::v4(), 3000}};
    std::cout << "Server on :3000\n";
    for (;;) std::make_shared<Session>(acceptor.accept())->start();
}
